// ─── Helpers ──────────────────────────────────────────────────────────────────

/** Returns a category key if the message is a venue search, else null. Order matters. */
export function detectVenueCategory(text: string): string | null {
  const t = text.toLowerCase();
  if (/\bgym\b|gyms|workout|fitness|weightlift|crossfit|\bmma\b|combat|spinning/.test(t)) return 'gym';
  // Checked before "lagoon" so a prompt mentioning both (e.g. the "Spa &
  // Lagoons" category card, "...spa or lagoon evening...") resolves to the
  // spa wizard, matching that card's own category id — a query that's
  // genuinely lagoon-only never contains a spa keyword, so this ordering
  // doesn't change matching for lagoon-only prompts.
  if (/\bspa\b|saunas?|steam room|wellness|recovery/.test(t)) return 'spa';
  if (/lagoon|hot spring|geothermal|thermal pool/.test(t)) return 'lagoon';
  if (/\byoga\b|pilates|vinyasa|yin yoga|hot yoga/.test(t)) return 'yoga';
  if (/\bpool\b|pools|swimming|swim lane/.test(t)) return 'swimming';
  if (/\bgolf\b|golfing|driving range/.test(t)) return 'golf';
  return null;
}
